import{_ as a,v as t,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const h=JSON.parse('{"title":"Week 7 | ESP32 联网控制舵机小成品","description":"","frontmatter":{"title":"Week 7 | ESP32 联网控制舵机小成品","date":"2026-04-14T00:00:00.000Z","tags":["课程周志","ESP32","WiFi控制","舵机"],"cover":"/code2real_blog/posts/week7/tung.jpg"},"headers":[],"relativePath":"posts/week7.md","filePath":"posts/week7.md"}'),i={name:"posts/week7.md"};function s(p,e,l,n,d,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>第七周继续进行 ESP32 实践。本周把 WiFi 联网和舵机控制组合起来，完成一个可以实际响应指令的小成品。</p><hr><img src="/code2real_blog/posts/week7/tung.jpg" alt="Week 7 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的重点是把上一周的基础控制扩展成一个小系统。开发板需要先接入 WiFi，再根据网络端传来的控制信息改变舵机角度。相比单独点亮 LED，这类任务已经包含连接、解析、执行三个环节。</p><p>学习内容主要包括 ESP32 的 WiFi 连接流程、舵机控制方式、控制指令处理和串口调试。这里不再只是验证单个语法点，而是检查不同模块能否在同一个程序中稳定配合。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先单独确认 ESP32 能够连接网络，再测试舵机是否能按指定角度转动。两个部分都能运行后，再把 WiFi 逻辑和舵机控制逻辑合并，形成一个完整流程。</p><p>调试时主要依靠串口输出观察状态，例如是否成功连接 WiFi、是否收到控制指令、指令解析结果是什么，以及舵机动作是否与预期一致。这个过程比上一周更接近真实项目，因为问题往往出现在模块交界处。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最明显的问题是故障来源变多。舵机不动时，原因可能是供电不足、信号线接错、控制角度设置不合理，也可能是网络指令根本没有传到程序里。不能看到现象就直接改代码，必须先判断问题在哪一层。</p><p>另外，舵机对供电和信号比较敏感。如果供电不稳定，程序逻辑正确也可能出现动作异常。这个问题提醒我，嵌入式项目不能只看代码，还要把硬件条件当成系统的一部分。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>本周让我从基础控制推进到了小型系统实现。ESP32 不再只是单独控制一个引脚，而是同时承担联网、处理指令和驱动执行机构的任务。</p><p>这个小成品规模不大，但意义比较明确：它把代码、网络和硬件动作串成了完整链路。后续如果继续完善，可以在控制界面、动作稳定性和异常处理上继续优化。</p><p><video src="/code2real_blog/posts/week7/1.mp4" controls></video></p>',16)])])}const k=a(i,[["render",s]]);export{h as __pageData,k as default};
